import{_ as a,o as t,c as b,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"先驱者","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/通用及综合类/先驱者.md","filePath":"4.资源分区/6.技艺及称号/通用及综合类/先驱者.md"}'),s={name:"4.资源分区/6.技艺及称号/通用及综合类/先驱者.md"};function o(d,e,l,_,i,c){return t(),b("div",null,[...e[0]||(e[0]=[r("h1",{id:"先驱者",tabindex:"-1"},[p("先驱者 "),r("a",{class:"header-anchor",href:"#先驱者","aria-label":'Permalink to "先驱者"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：绯红庆典040")])])],-1),n('<h1 id="先驱者-1" tabindex="-1">先驱者 <a class="header-anchor" href="#先驱者-1" aria-label="Permalink to &quot;先驱者&quot;">​</a></h1><p>先驱者<br> 技艺组<br> 一败再败，危亡之际。饥膏草野，饿殍遍地。无边黑夜之中，总有人不断前行，寻找一个光明的未来。</p><p>销焰无烟<br> C+1000<br> 如此炙热，让海水沸腾。如此平静，见不到一丝火焰。如此热烈，人群鼓掌称好。如此冰冷，那个人有着悲哀的结局。<br> 以热驱毒，使用整轮动作，灼伤自己与至少一名触及范围内愿意配合的友方单位，这么做离不开他人的支持，这使得你和他都立刻承受1点燃烧点数（该燃烧点数可以以每轮1点的速度自然恢复），再立刻清除4点异常点数（医疗池96）。然而过于激进的行为被稍加利用便成为了侵略的口实，若因此清除的异常点，其施加者在当前场景中，则其对因为该能力得到治疗的人进行攻击时额外获得3士气加值。</p><p>天降太平<br> C+1000<br> 天父天兄，普照万民，今天下大乱，我等顺天父天兄的话语，让太平降临世间。<br> 使用一个标准动作并支付1意志力向天呼喊祈求天父天兄的保佑上身。你的触及范围内的友方单位（随从不计入，集群生物只算一个）可以与你一同呼喊（这不消耗动作），这让【你自身】在当前场景的攻击检定获得呼喊人数（你+一同呼唤的友方单位）*6的士气加值，上限为你的决心属性。与你一同呼喊的友方单位，可以以自由动作宣称天父降临或者其他什么神灵降临，这会让你因为这个能力获得的攻击检定上的加值在持续时间内转移给他，你和其他单位也可以在自己的回合这么做，让加值再次转移，每因此转移两次，这个加值在当前场景中永久减1。重复释放该技艺也不会刷新加值（如果人数*8少于当前加值的话则加值也会相应下降。），只会更新呼唤者名单。</p><p>务新为用<br> C+1000<br> 我们的思想与制度并不弱于他们，只不过他们有些厉害的兵器。只要拿来用用，我们就不会输。<br> 让自身效仿最新的技术，提升自己的实力，你在支付意志力获得攻击上的加值时，可以额外支付1点意志力额外获得智力一半的士气加值，你在支付意志力获得防御上的士气加值时，可以额外支付1意志力额外获得智力属性一半的盔甲防御。</p><p>上书求变<br> C+1000<br> 已经不能再这样了，我们要变化，我们必须改变什么。<br> 效仿，学习，在一场战斗开始时，你将效仿敌人的能力，让你在这场战斗中获得以下效果之一：<br> 1、本次战斗中每轮获得2点用于攻击的额外AP<br> 2、本质战斗中每轮一次你可以重骰一次攻击检定，但必须接受新的结果。<br> 3、在本次战斗中你无视多次攻击减值<br> 然而这样的效仿离不开敌人的帮助，所以你会得到什么效果由【敌人】进行选择（这个选择不受思维控制、支配、迷情点数等的影响，完全由敌人的自我意志决定），施展该能力时，你需要选定能够精准定位的一名敌人，对方的眼前会出现你所呈之策，从中选择其一作为你该能力生效的部分。<br> 改革，求新，进入战斗中你的每一轮开始时你可以选择是否承受代清贵族的不满化作的3点不可豁免的毒素点数，若选择承受，则直到你的下一轮开始，你的攻击检定始终获得1点士气上的附加成功，与对老妖婆特攻的【法破】特性，若选择不承受，则本技艺在当前战斗中失效（包括上面由敌人选择得到的效果也会失效。）</p><p>神助拳<br> C+1000<br> 向神明祈祷，即使神明可能并不存在，我们的敌人如怪物般强大，如怪物般凶恶，纵然如此，我们是为了自己的兄弟而战，因此决不能退缩。<br> 使用迅捷动作并支付2意志力请求神明降临，即使他可能并不存在。如果你使用棍子就请孙悟空，如果你使用耙子就请猪八戒，为同伴而战的勇气驱使我们一同前进。你的下一次攻击时，你先从闪避防御、盔甲防御、天生防御中选择一项，受到此次攻击的敌人需要用意志豁免对抗此次攻击的伤害出目，若失败，则在当前场景中，目标拥有的，由你所选择的防御类型，下降你的决心一半的数值，这是一个C级别心灵来源的效果，他们不会因为神明恐惧，而是为我们的勇气而恐惧。</p><p>彻底推翻<br> B+2000<br> 已经没救了，这个王朝已经腐朽，我们不能再畏惧，我们必须进行一场轰轰烈烈地改变，我们必须推翻这个王朝。<br> 每场景一次，你可以使用一个标准动作支付3意志力来筹备一场轰轰烈烈的武装起义，这让你下轮的第一次攻击获得自身智力*1的器械加值，伤害增加一倍，攻击出目增加一半，但若你在进行下轮第一次攻击之前受到合计不低于你【生命值上限】或【结构值上限一半】的伤害，则失去因此获得的器械加值，且伤害不会增加一倍。若不能彻底的革新，将留下隐患，因此得到加成的攻击结束后，若战斗仍未结束，则在当前场景中其对你进行攻击时你的防御承受场上存活敌人数*10的士气减值（集群生物在数量计算上视为1个）</p><p>先驱者之风<br> A+4000<br> 我们已经忍受了太多的失败，我们不能接受这样的屈辱，从青年开始，接下来是工人，接下来是农民，所有人都将走上街头，微风聚集为狂风，也许光芒就在不远的未来。<br> 一影片一次，你可以使用一个标准动作，鼓起勇气引领众人前行。让触及范围内的友方单位被你感召，成为你的被感召者，只要你没有进入无法战斗的状态，在当前场景中你就有一次机会，当你以外的一名被感召者死亡时，你可以令其凭借前行的意志立刻复活，这是A级心灵来源的复活效果，这个复活能力无法对你自身使用，且当你在鼓舞众人的同时，你的敌人也会察觉到你的气魄，只要对方有一定智力就能察觉到：你为友方提供了总计一次的复活机会，且只要你先无法战斗其他人就不会因为你的能力复活。 成为先驱者的勇气，你有吗？</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',11)])])}const m=a(s,[["render",o]]);export{f as __pageData,m as default};
